function ZonesStation({ onComplete, onBack }: { onComplete: () => void; onBack: () => void }) {
  const [gapIdx, setGapIdx] = useState(3); // start at full employment
  const [revealed, setRevealed] = useState(false);

  const scenario = THREE_ZONES_SCENARIOS[gapIdx];
  const gap = scenario.gap;

  const zoneColor = scenario.zone === "keynesian" ? "#3b82f6" : scenario.zone === "neoclassical" ? "#ef4444" : "#f59e0b";
  const zoneName = scenario.zone === "keynesian" ? "Keynesian Zone" : scenario.zone === "neoclassical" ? "Neoclassical Zone" : "Intermediate Zone";

  // Simple AS curve visualization with zone shading
  const W = 300, H = 160;

  return (
    <div className="max-w-2xl mx-auto">
      <div className="mb-6">
        <h2 className="font-display font-bold text-xl text-foreground mb-1">Three Zones Explorer</h2>
        <p className="text-sm text-muted-foreground">Slide the output gap to see how the economy's position on the AS curve changes what policy can achieve.</p>
      </div>

      {/* AS curve zones diagram */}
      <div className="bg-card border border-card-border rounded-xl p-5 mb-5">
        <div className="flex justify-center mb-3">
          <svg viewBox={`0 0 ${W} ${H}`} className="w-full max-w-xs" style={{ maxHeight: "160px" }}>
            {/* Zone backgrounds */}
            <rect x={15} y={10} width={80} height={H-20} fill="#3b82f6" fillOpacity={0.08}/>
            <rect x={95} y={10} width={80} height={H-20} fill="#f59e0b" fillOpacity={0.08}/>
            <rect x={175} y={10} width={110} height={H-20} fill="#ef4444" fillOpacity={0.08}/>
            {/* Zone labels */}
            <text x={55} y={25} textAnchor="middle" fontSize={8} fill="#3b82f6" fillOpacity={0.7}>Keynesian</text>
            <text x={135} y={25} textAnchor="middle" fontSize={8} fill="#f59e0b" fillOpacity={0.7}>Intermediate</text>
            <text x={220} y={25} textAnchor="middle" fontSize={8} fill="#ef4444" fillOpacity={0.7}>Neoclassical</text>
            {/* AS curve: flat, then sloping, then vertical */}
            <path d="M15,120 Q95,115 135,80 Q165,50 185,20" fill="none" stroke="#f59e0b" strokeWidth={2.5}/>
            {/* Axes */}
            <line x1={15} y1={10} x2={15} y2={H-5} stroke="currentColor" strokeOpacity={0.3} strokeWidth={1}/>
            <line x1={15} y1={H-5} x2={285} y2={H-5} stroke="currentColor" strokeOpacity={0.3} strokeWidth={1}/>
            <text x={150} y={H-1} textAnchor="middle" fontSize={8} fill="currentColor" fillOpacity={0.4}>Real GDP →</text>
            <text x={8} y={80} textAnchor="middle" fontSize={8} fill="currentColor" fillOpacity={0.4} transform="rotate(-90,8,80)">Price Level</text>
            {/* Current position indicator */}
            {(() => {
              const positions = [30, 55, 115, 135, 190, 225];
              const yPositions = [118, 116, 95, 80, 45, 28];
              const x = positions[gapIdx], y = yPositions[gapIdx];
              return <circle cx={x} cy={y} r={7} fill={zoneColor} fillOpacity={0.9} stroke="white" strokeWidth={2}/>;
            })()}
          </svg>
        </div>

        {/* Gap slider */}
        <div className="mb-3">
          <div className="flex items-center justify-between mb-1 text-xs text-muted-foreground">
            <span>← Deep Recession</span>
            <span className="font-bold text-foreground" style={{ color: zoneColor }}>{scenario.label}</span>
            <span>Overheated →</span>
          </div>
          <input type="range" aria-label="Slider" min={0} max={5} step={1} value={gapIdx}
            onChange={e => { setGapIdx(parseInt(e.target.value)); setRevealed(false); }}
            data-testid="zones-slider"
            className="w-full h-3 appearance-none rounded-full cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-6 [&::-webkit-slider-thumb]:h-6 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:shadow-lg [&::-webkit-slider-thumb]:border-3 [&::-webkit-slider-thumb]:border-white [&::-webkit-slider-thumb]:bg-white [&::-moz-range-thumb]:w-6 [&::-moz-range-thumb]:h-6 [&::-moz-range-thumb]:rounded-full [&::-moz-range-thumb]:border-2 [&::-moz-range-thumb]:border-white [&::-moz-range-thumb]:bg-white"
            style={{ background: `linear-gradient(to right, #3b82f6, #f59e0b, #ef4444)` }}
          />
        </div>

        <div className="grid grid-cols-3 gap-2 mb-4">
          <div className="text-center p-2 bg-muted rounded-lg">
            <div className="text-xs text-muted-foreground">Output Gap</div>
            <div className={`font-bold text-sm mt-0.5`} style={{ color: zoneColor }}>{gap > 0 ? "+" : ""}{gap}%</div>
          </div>
          <div className="text-center p-2 bg-muted rounded-lg">
            <div className="text-xs text-muted-foreground">Zone</div>
            <div className="font-bold text-xs mt-0.5" style={{ color: zoneColor }}>{zoneName}</div>
          </div>
          <div className="text-center p-2 bg-muted rounded-lg">
            <div className="text-xs text-muted-foreground">Stimulus Effect</div>
            <div className="font-bold text-xs mt-0.5 text-foreground">
              {scenario.zone === "keynesian" ? "Mostly output ↑" : scenario.zone === "neoclassical" ? "Mostly prices ↑" : "Mixed"}
            </div>
          </div>
        </div>

        {!revealed ? (
          <button onClick={() => setRevealed(true)}
            className="w-full py-2.5 rounded-xl bg-primary/10 border border-primary/20 text-primary text-sm font-semibold hover:bg-primary/20 transition-all">
            Show Policy Prescription
          </button>
        ) : (
          <div className="p-3 rounded-xl border text-xs text-foreground leading-relaxed" style={{ borderColor: zoneColor + "60", backgroundColor: zoneColor + "10" }}>
            <strong>Policy:</strong> {scenario.policy}
          </div>
        )}
      </div>

      <NavButtons onBack={onBack} onNext={revealed ? onComplete : undefined} nextDisabled={!revealed} nextLabel="Mark Complete ✓" />
      {!revealed && <p className="text-xs text-center text-muted-foreground mt-2">Explore the slider and reveal at least one policy prescription to mark complete.</p>}
    </div>
  );
}

